import{_ as t,o as s,c as a,ag as o}from"./chunks/framework.DlJzNSsD.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md","lastUpdated":1778941218000}'),n={name:"architecture.md"};function r(i,e,c,d,l,p){return s(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>A single-page tour of how ClawTerm is put together. Read this once before changing any code that touches tabs, panes, polling, the show/hide pipeline, the PTY layer, or session persistence.</p><blockquote><p><strong>Source-of-truth invariant.</strong> When this document and the code disagree, the code wins. Update this page in the same commit that changes the design.</p></blockquote><h2 id="stack" tabindex="-1">Stack <a class="header-anchor" href="#stack" aria-label="Permalink to &quot;Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Tech</th><th>Why</th></tr></thead><tbody><tr><td>Desktop shell</td><td><a href="https://v2.tauri.app/" target="_blank" rel="noreferrer">Tauri 2</a></td><td>Native window, OS APIs, autoupdater, signing</td></tr><tr><td>Backend</td><td>Rust</td><td>Process introspection (<code>proc_*</code> on macOS), git, fs, server health checks</td></tr><tr><td>Frontend</td><td>TypeScript + Vite</td><td>Application logic, state machine, UI</td></tr><tr><td>Terminal</td><td><a href="https://xtermjs.org/" target="_blank" rel="noreferrer">xterm.js</a> v6</td><td>Cell rendering, scrollback, addons</td></tr><tr><td>PTY</td><td><a href="https://github.com/marc2332/tauri-pty" target="_blank" rel="noreferrer"><code>tauri-pty</code></a></td><td>OS pseudo-terminal bridge</td></tr></tbody></table><p>The <strong>only</strong> language boundary is the Tauri IPC layer (<code>invoke()</code> from JS, <code>#[tauri::command]</code> in Rust). Everything else lives on one side or the other.</p><h2 id="source-layout" tabindex="-1">Source layout <a class="header-anchor" href="#source-layout" aria-label="Permalink to &quot;Source layout&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/                           ← TypeScript frontend</span></span>
<span class="line"><span>├── main.ts                    ← Entry point — instantiates TerminalManager</span></span>
<span class="line"><span>├── terminal-manager.ts        ← Top-of-tree owner; init, polling, projects, lifecycle</span></span>
<span class="line"><span>├── tab.ts                     ← Tab + split tree (binary SplitNode); show/hide pipeline</span></span>
<span class="line"><span>├── pane.ts                    ← Single xterm.js terminal + PTY + scroll lock + write batching</span></span>
<span class="line"><span>├── pane-webgl.ts              ← Shared LRU pool of WebGL contexts (cap: 6)</span></span>
<span class="line"><span>├── output-analyzer.ts         ← Regex matching against PTY output (debounced)</span></span>
<span class="line"><span>├── matchers.ts                ← Default agent / server / error patterns</span></span>
<span class="line"><span>├── tab-state.ts               ← PaneState / TabState data shapes + helpers</span></span>
<span class="line"><span>├── tab-polling.ts             ← Adaptive idle-timeout math (95th-percentile output gap)</span></span>
<span class="line"><span>├── session.ts                 ← Load/save the V2 session JSON via Rust</span></span>
<span class="line"><span>├── config.ts                  ← Defaults, deepMerge, validation, reload</span></span>
<span class="line"><span>├── config-types.ts            ← TypeScript shape of the config schema</span></span>
<span class="line"><span>├── notifications.ts           ← OS notifications via @tauri-apps/plugin-notification</span></span>
<span class="line"><span>├── server-tracker.ts          ← Polled localhost port health checks</span></span>
<span class="line"><span>├── worktree-base.ts           ← resolveWorktreeBase() — the three-mode path resolver</span></span>
<span class="line"><span>├── worktree-actions.ts        ← Frontend worktree orchestration (dialog → IPC → tab)</span></span>
<span class="line"><span>├── worktree-dialog.ts         ← Branch picker UI for new worktree tabs</span></span>
<span class="line"><span>├── logger.ts                  ← Console-only logger with in-memory ring buffer (2000)</span></span>
<span class="line"><span>├── perf.ts                    ← perfMetrics — tiny instrumentation harness</span></span>
<span class="line"><span>└── ...                        ← UI bits: command palette, sidebar, settings, dialogs</span></span>
<span class="line"><span></span></span>
<span class="line"><span>src-tauri/src/                 ← Rust backend</span></span>
<span class="line"><span>├── main.rs                    ← Tauri command registration, config + session paths</span></span>
<span class="line"><span>├── worktree.rs                ← git worktree add/remove/lock + repo-root resolution</span></span>
<span class="line"><span>├── git_info.rs                ← branch + status (with caching)</span></span>
<span class="line"><span>├── process_info.rs            ← Batched poll_pane_info: process + cwd + git in one IPC</span></span>
<span class="line"><span>├── project_info.rs            ← Detect project name from package.json / Cargo.toml / go.mod</span></span>
<span class="line"><span>└── server_check.rs            ← TCP probe for localhost port health</span></span></code></pre></div><h2 id="object-hierarchy" tabindex="-1">Object hierarchy <a class="header-anchor" href="#object-hierarchy" aria-label="Permalink to &quot;Object hierarchy&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TerminalManager (singleton)</span></span>
<span class="line"><span>├── Project[]                       (each owns a subset of tab IDs — sidebar grouping)</span></span>
<span class="line"><span>├── Map&lt;string, Tab&gt;                (all tabs across all projects)</span></span>
<span class="line"><span>├── NotificationManager</span></span>
<span class="line"><span>├── ServerTracker                   (polls localhost ports)</span></span>
<span class="line"><span>├── TabRenderer                     (sidebar DOM)</span></span>
<span class="line"><span>└── WorkspacePanel                  (worktree list panel)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Tab</span></span>
<span class="line"><span>├── root: SplitNode                 (binary tree — see below)</span></span>
<span class="line"><span>├── panes: Pane[]                   (flat list mirror of leaves, for iteration)</span></span>
<span class="line"><span>├── focusedPane: Pane</span></span>
<span class="line"><span>├── state: TabState                 (derived from pane states each poll)</span></span>
<span class="line"><span>└── (per-tab polling, fit, show/hide)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SplitNode (discriminated union, src/tab.ts:32)</span></span>
<span class="line"><span>├── { type: &quot;leaf&quot;, pane: Pane }</span></span>
<span class="line"><span>└── { type: &quot;split&quot;, direction, ratio, children: [SplitNode, SplitNode] }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pane</span></span>
<span class="line"><span>├── terminal: xterm.js Terminal</span></span>
<span class="line"><span>├── pty: tauri-pty IPty</span></span>
<span class="line"><span>├── analyzer: OutputAnalyzer        (regex matchers — feeds events back to Tab)</span></span>
<span class="line"><span>├── state: PaneState                (activity, agent, gitStatus, statusLine, ...)</span></span>
<span class="line"><span>├── webgl: WebGLManager             (lazy; LRU pool eviction)</span></span>
<span class="line"><span>└── (write batching, scroll lock, footer, gutter, paste confirm)</span></span></code></pre></div><p>The <strong>split tree</strong> is a real binary tree. Splitting a pane replaces a <code>SplitLeaf</code> with a <code>SplitBranch</code> whose two children are the old leaf and a new one. Closing a pane collapses the branch back into its sibling. The flat <code>panes: Pane[]</code> mirror exists for fast iteration (<code>for (const pane of tab.panes)</code> is everywhere); <code>tab.root</code> is the source of truth for layout.</p><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h2><h3 id="init-cold-start" tabindex="-1">Init (cold start) <a class="header-anchor" href="#init-cold-start" aria-label="Permalink to &quot;Init (cold start)&quot;">​</a></h3><p><code>src/main.ts</code> instantiates <code>TerminalManager</code> and calls <code>await manager.init()</code>. The init sequence (<code>src/terminal-manager.ts:145</code>) runs in this order:</p><ol><li><strong>Load config</strong> from <code>~/.config/clawterm/config.json</code> (deepMerge with defaults, validate, fall back per-field on bad values)</li><li><strong>Construct subsystems</strong> — <code>NotificationManager</code>, <code>ServerTracker</code>, <code>TabRenderer</code>, <code>WorkspacePanel</code></li><li><strong>Apply CSS</strong> — theme tokens injected from config</li><li><strong>Load session in parallel</strong> with synchronous DOM setup — <code>loadSession()</code> reads <code>session.json</code> via Rust, validates the recursive split tree, normalizes V1 → V2</li><li><strong>Render shell DOM</strong> — sidebar, titlebar, status bar, project tabs</li><li><strong>Restore tabs</strong> — for each project, restore the active tab first (responsiveness), then the rest with rAF yields between</li><li><strong>Fall back to a fresh tab</strong> if every restore failed</li><li><strong>Start the central poll</strong> (<code>startCentralPoll()</code>)</li><li><strong>Fire the legacy-worktree hint</strong> (non-blocking, async, see <a href="./features/worktrees">Worktrees</a>)</li></ol><p>The <code>await manager.init()</code> resolves once the first tab is interactive. Polling and the legacy hint continue in the background.</p><h3 id="shutdown" tabindex="-1">Shutdown <a class="header-anchor" href="#shutdown" aria-label="Permalink to &quot;Shutdown&quot;">​</a></h3><p><code>src/main.ts:29</code> registers a <code>beforeunload</code> listener that calls <code>await manager.flushSession()</code> synchronously. This serializes the current split tree of every tab into JSON and writes it via Rust before the window closes. Session writes during normal operation are debounced (~3 s) to coalesce rapid state changes.</p><h2 id="the-polling-pipeline" tabindex="-1">The polling pipeline <a class="header-anchor" href="#the-polling-pipeline" aria-label="Permalink to &quot;The polling pipeline&quot;">​</a></h2><p>There is <strong>one</strong> central poll loop (<code>startCentralPoll()</code> in <code>terminal-manager.ts</code>). It uses a single <code>setInterval</code> keyed off <code>config.advanced.pollIntervalMs</code> (foreground) and falls back to <code>backgroundPollIntervalMs</code> for tabs that aren&#39;t visible. Each tick:</p><ol><li><strong>Snapshot the active tab ID</strong> so the loop is robust against tab switches mid-poll</li><li><strong>Concurrently poll</strong> the active tab and any background tab whose interval has elapsed</li><li><strong>Refresh xterm renderers</strong> every ~10 ticks (recovers from silent WebGL context loss)</li><li><strong>Recompute tab snapshots</strong> and re-render the sidebar if anything changed</li><li><strong>Update the status bar</strong></li></ol><p>A single tab&#39;s poll (<code>Tab.pollProcessInfo()</code> → <code>pollPane()</code> per pane) is <strong>two</strong> IPC calls:</p><ul><li><code>plugin:pty|foreground_pid</code> — get the shell&#39;s foreground process group via the PTY fd</li><li><code>poll_pane_info</code> — <strong>batched</strong> call returning <code>{ process_name, fg_pid, cwd, full_cwd, git_status, project_name, has_children }</code> in one round trip</li></ul><p>This batch replaced 5–7 sequential IPC calls. After 5+ consecutive idle polls, expensive work (CWD, git, project name) is skipped via the <code>skipExpensive</code> flag.</p><p><strong>Agent state detection</strong> combines two signals:</p><ul><li><strong>Process name match</strong> (<code>AGENT_PROCESS_MAP</code> in <code>src/matchers.ts</code>) — claude, aider, copilot, cursor, codex, gemini. The TUI process name is checked even when the shell looks idle, because Claude Code etc. don&#39;t fork.</li><li><strong>OSC 9;4 progress sequences</strong> parsed by <code>osc-handler.ts</code> — the most reliable working/idle signal when the agent emits it.</li><li><strong>Output regex matchers</strong> in <code>output-analyzer.ts</code> — fallback for agents that don&#39;t speak OSC.</li></ul><p>The <strong>adaptive idle timeout</strong> (<code>tab-polling.ts:32</code>) uses the 95th percentile of recent output gaps × 2, clamped to 15–60 s, to decide when an agent has actually paused versus is just thinking. When OSC is active, it falls back to a tight 5 s window because OSC is ground truth.</p><h2 id="the-show-hide-pipeline" tabindex="-1">The show/hide pipeline <a class="header-anchor" href="#the-show-hide-pipeline" aria-label="Permalink to &quot;The show/hide pipeline&quot;">​</a></h2><p>This is the most performance-sensitive part of the codebase. Read the full prior-art trail in issues #167, #182, #184, #227, #305, and #419 before changing it. The current architecture is documented in <code>pane.ts:64-81</code> and below.</p><h3 id="tab-hide-tab-ts-1322" tabindex="-1"><code>Tab.hide()</code> (<code>tab.ts:1322</code>) <a class="header-anchor" href="#tab-hide-tab-ts-1322" aria-label="Permalink to &quot;\`Tab.hide()\` (\`tab.ts:1322\`)&quot;">​</a></h3><ol><li><code>pane.lockScroll()</code> — captures <code>lockedDistanceFromBottom</code> and <code>lockedBufferLength</code> (the tripwire baseline). <strong>Distance from bottom</strong>, not <code>viewportY</code>, because xterm&#39;s scrollback can be trimmed under us during the hidden window (#305 / #419).</li><li><code>pane.saveScrollPosition()</code> — DOM-level <code>scrollTop</code> backup; defense in depth alongside CSS <code>visibility: hidden</code>.</li><li>Cancel any pending show() rAF — prevents stale focus stealing.</li><li><code>pane.setVisible(false)</code> — flips <code>tabVisible</code>, queues subsequent PTY data into <code>pendingWriteData[]</code> instead of flushing per frame, trims the scrollback to <code>HIDDEN_SCROLLBACK = 1000</code> lines (skipped when <code>userScrolledUp</code> is true so the user&#39;s view isn&#39;t yanked, #419 Fix 2), and pauses the gutter timer.</li></ol><h3 id="tab-show-tab-ts-1261-—-2-frame-raf-chain" tabindex="-1"><code>Tab.show()</code> (<code>tab.ts:1261</code>) — 2-frame rAF chain <a class="header-anchor" href="#tab-show-tab-ts-1261-—-2-frame-raf-chain" aria-label="Permalink to &quot;\`Tab.show()\` (\`tab.ts:1261\`) — 2-frame rAF chain&quot;">​</a></h3><p>The pipeline used to be 4 frames (~67 ms); collapsing it to 2 (~33 ms) is intentional and load-bearing for tab-switch responsiveness.</p><p><strong>Frame 1</strong> — destabilizing operations:</p><ol><li><code>pane.restoreScrollPosition()</code> — DOM scrollTop restore</li><li><code>pane.forceFit()</code> — xterm reflow to current container dimensions, bypassing the 300 ms output-activity deferral</li><li><code>pane.setVisible(true)</code> — restores original scrollback cap, schedules an rAF flush of any queued PTY writes, resumes gutter timer</li><li><code>pane.activateWebGL(true)</code> — picks up a context from the LRU pool (or creates one if pool isn&#39;t full)</li><li><code>this.refreshAllPanes()</code> — xterm refresh</li></ol><p><strong>Frame 2</strong> — single authoritative restore:</p><ol><li><code>pane.unlockScroll()</code> — performs the <strong>only</strong> scroll restoration after a tab transition. Uses <code>lockedDistanceFromBottom</code> to compute the new <code>viewportY</code>. The Fix 5 invariant tripwire (<code>pane.ts:1108</code>) fires here if the buffer length changed in an unexpected way (the legitimate #305 trim is gated via <code>trimmedDuringHide</code>).</li><li><code>pane.refreshScrollPill()</code> — reattaches the &quot;jump to bottom&quot; pill if the user is still scrolled up</li><li><code>this.transitioning = false</code> — re-enables ResizeObserver fits</li><li>Focus the focused pane</li></ol><h3 id="why-it-s-structured-this-way" tabindex="-1">Why it&#39;s structured this way <a class="header-anchor" href="#why-it-s-structured-this-way" aria-label="Permalink to &quot;Why it&#39;s structured this way&quot;">​</a></h3><p>Every prior fix in this lineage failed because it locked <code>viewportY</code> (an index into a buffer that the #305 path mutates underneath the lock). #419 switched to <strong>distance from bottom</strong> because the bottom of the buffer is the only stable reference point across a hide/show cycle: xterm only ever trims the front of the scrollback, never lines near the bottom. See <code>pane.ts:1071-1133</code> and the prior-art comment in #419 for the full archaeology.</p><h2 id="the-pty-→-xterm-pipeline" tabindex="-1">The PTY → xterm pipeline <a class="header-anchor" href="#the-pty-→-xterm-pipeline" aria-label="Permalink to &quot;The PTY → xterm pipeline&quot;">​</a></h2><p><code>Pane.start()</code> (<code>pane.ts:453</code>) spawns a PTY via <code>tauri-pty.spawn(shell, args, opts)</code>, awaits <code>pty._init</code>, then captures the OS PID via <code>plugin:pty|child_pid</code>. From there:</p><ol><li><code>pty.onData(Uint8Array)</code> fires for every PTY chunk</li><li><strong>Output gap tracking</strong> — gap duration since the previous chunk is recorded into <code>pane.outputGaps[]</code> (capped at 20) for adaptive idle timeout</li><li><strong>OSC bypass</strong> — if the OSC handler reports <code>oscActive &amp;&amp; !oscProgressActive</code> and the chunk is small, skip the timestamp update (the OSC stream is ground truth for activity)</li><li><strong>Feed <code>OutputAnalyzer</code></strong> — the analyzer accumulates a 4 KB rolling buffer, strips ANSI, runs regex matchers (debounced 100 ms), and fires <code>OutputEvent</code>s back to the Tab via <code>onOutputEvent</code></li><li><strong>Queue the write</strong> — the chunk is pushed onto <code>pendingWriteData[]</code> and a single <code>requestAnimationFrame</code> writes the merged buffer per frame (<code>flushWrites()</code>)</li></ol><h3 id="write-batching" tabindex="-1">Write batching <a class="header-anchor" href="#write-batching" aria-label="Permalink to &quot;Write batching&quot;">​</a></h3><p>Without rAF batching, <code>terminal.write()</code> runs once per PTY chunk and races <code>fitAddon.fit()</code> mid-reflow. The batching:</p><ul><li>merges all queued chunks into a <strong>reusable</strong> <code>Uint8Array</code> (<code>mergeBuffer</code>, never shrinks) — avoids per-frame allocation</li><li>uses a single <code>terminal.write(data, callback)</code> call so xterm can parse asynchronously and run our scroll-restoration in the callback (#257)</li><li>caps queued bytes at <code>MAX_HIDDEN_PENDING_BYTES = 128 KB</code> for hidden tabs (down from 512 KB in #305) to limit memory pressure with many tabs</li></ul><p>Hidden tabs <strong>don&#39;t</strong> flush — writes accumulate until <code>setVisible(true)</code> schedules a flush. This is the largest CPU win for many-tab workloads.</p><h2 id="output-analysis" tabindex="-1">Output analysis <a class="header-anchor" href="#output-analysis" aria-label="Permalink to &quot;Output analysis&quot;">​</a></h2><p><code>OutputAnalyzer</code> (<code>src/output-analyzer.ts</code>) runs a list of regex matchers against the PTY output stream, producing typed <code>OutputEvent</code>s that drive the tab state machine. Matchers live in <code>src/matchers.ts</code> and are grouped by purpose:</p><ul><li><strong>Agent-waiting</strong> — detects <code>[Y/n]</code>, &quot;Approve?&quot;, &quot;Do you want to proceed?&quot; etc. Triggers desktop notifications.</li><li><strong>Server-started</strong> — extracts port numbers from &quot;listening on port NNNN&quot; patterns. Hands off to <code>ServerTracker</code>.</li><li><strong>Error</strong> — &quot;Address already in use&quot;, &quot;Connection refused&quot;, and similar. Surfaces in the sidebar.</li><li><strong>Agent-working</strong> — scanned via <code>Tab.scanBufferForWorkingPatterns()</code> rather than the streaming analyzer.</li></ul><p>Every matcher has a cooldown (5–30 s) to prevent event spam. Matchers tagged <code>oscSuperseded</code> are skipped while OSC 9;4 is reporting progress, since OSC is the higher-confidence signal.</p><p><code>Tab.handleOutputEvent()</code> (<code>tab.ts:207</code>) is the single dispatch point. It updates <code>pane.state.activity</code> (<code>idle → running → agent-waiting → completed → idle</code>), increments action counts, stores events in <code>analyzer.eventHistory[]</code> for the gutter timeline, and calls <code>notifications.dispatch()</code> if the tab isn&#39;t currently focused.</p><h2 id="rust-↔-js-boundary" tabindex="-1">Rust ↔ JS boundary <a class="header-anchor" href="#rust-↔-js-boundary" aria-label="Permalink to &quot;Rust ↔ JS boundary&quot;">​</a></h2><p>Every command lives in <code>src-tauri/src/</code> and is registered in <code>main.rs</code>. Frontend calls come exclusively through <code>invoke()</code> (or <code>invokeWithTimeout()</code> from <code>src/utils.ts</code>, which adds an abort timeout). Grouped by purpose:</p><table tabindex="0"><thead><tr><th>Purpose</th><th>Most-used commands</th><th>Lives in</th></tr></thead><tbody><tr><td><strong>PTY</strong> (plugin)</td><td>\`plugin:pty</td><td>foreground_pid<code>, </code>plugin:pty</td></tr><tr><td><strong>Polling</strong></td><td><code>poll_pane_info</code> (batched)</td><td><code>process_info.rs</code></td></tr><tr><td><strong>Worktree</strong></td><td><code>create_worktree</code>, <code>lock_worktree</code>, <code>find_repo_root</code>, <code>list_branches</code>, <code>unlock_worktree</code>, <code>remove_worktree</code></td><td><code>worktree.rs</code></td></tr><tr><td><strong>Git</strong></td><td><code>get_git_branch</code>, <code>get_git_status</code></td><td><code>git_info.rs</code></td></tr><tr><td><strong>Server health</strong></td><td><code>check_port</code></td><td><code>server_check.rs</code></td></tr><tr><td><strong>Persistence</strong></td><td><code>read_session</code>, <code>write_session</code>, <code>write_config</code></td><td><code>main.rs</code></td></tr><tr><td><strong>Filesystem</strong></td><td><code>validate_dir</code>, <code>validate_shell</code>, <code>has_legacy_in_repo_worktrees</code></td><td><code>main.rs</code></td></tr><tr><td><strong>Project info</strong></td><td><code>get_project_info</code></td><td><code>project_info.rs</code></td></tr></tbody></table><p>There is no shared state across commands beyond what each command derives from its arguments and the filesystem. All Rust handlers are stateless functions; persistence is whatever each command writes to disk.</p><h2 id="session-persistence" tabindex="-1">Session persistence <a class="header-anchor" href="#session-persistence" aria-label="Permalink to &quot;Session persistence&quot;">​</a></h2><p>Format and behaviour:</p><ul><li><strong>Path</strong>: <code>~/.config/clawterm/session.json</code></li><li><strong>Format</strong>: V2 — <code>{ version: 2, projects: SessionProject[], activeProject: number }</code>. V1 (<code>{ tabs, activeIndex }</code>) is auto-wrapped into a single project on load.</li><li><strong>Per-tab record</strong>: <code>{ title?, cwd, splits?, pinned?, muted?, manualTitle?, worktreePath?, repoRoot? }</code></li><li><strong>Splits</strong>: recursive <code>SessionSplitNode</code> mirroring the in-memory <code>SplitNode</code> tree.</li><li><strong>Save cadence</strong>: debounced 3 s during normal operation; synchronous flush on shutdown (<code>main.ts:29</code>)</li><li><strong>Load</strong>: <code>loadSession()</code> validates the split tree recursively, returns <code>null</code> on any structural error, falls through to a fresh tab.</li></ul><p>The session does <strong>not</strong> persist scrollback, agent state, or any runtime data. Only structural information needed to recreate the same layout in the same cwds.</p><h2 id="where-to-find-things" tabindex="-1">Where to find things <a class="header-anchor" href="#where-to-find-things" aria-label="Permalink to &quot;Where to find things&quot;">​</a></h2><table tabindex="0"><thead><tr><th>If you&#39;re touching...</th><th>Start here</th></tr></thead><tbody><tr><td>Tabs / projects / sidebar UI</td><td><code>terminal-manager.ts</code></td></tr><tr><td>The split tree</td><td><code>tab.ts</code> (look for <code>SplitNode</code>)</td></tr><tr><td>A single terminal&#39;s behaviour</td><td><code>pane.ts</code></td></tr><tr><td>The show/hide / scroll lock</td><td><code>tab.ts:1261-1349</code> + <code>pane.ts:1071-1133</code></td></tr><tr><td>Write batching, fit timing</td><td><code>pane.ts:843-932</code></td></tr><tr><td>Agent state detection</td><td><code>output-analyzer.ts</code> + <code>matchers.ts</code> + <code>tab.ts:207</code></td></tr><tr><td>Polling logic</td><td><code>terminal-manager.ts</code> + <code>tab.ts:868-1011</code></td></tr><tr><td>Adaptive idle math</td><td><code>tab-polling.ts:32</code></td></tr><tr><td>Rust-side process probing</td><td><code>src-tauri/src/process_info.rs</code></td></tr><tr><td>Worktrees</td><td><a href="./features/worktrees"><code>docs/features/worktrees.md</code></a></td></tr><tr><td>Config schema</td><td><code>config-types.ts</code> (types) + <code>config.ts</code> (defaults + validation)</td></tr><tr><td>Keybinding dispatch</td><td><code>keybinding-handler.ts</code></td></tr><tr><td>Notifications</td><td><code>notifications.ts</code></td></tr></tbody></table><h2 id="things-to-know-before-changing-this-code" tabindex="-1">Things to know before changing this code <a class="header-anchor" href="#things-to-know-before-changing-this-code" aria-label="Permalink to &quot;Things to know before changing this code&quot;">​</a></h2><ul><li><strong>The 2-frame rAF chain in <code>Tab.show()</code> is load-bearing.</strong> Adding a third frame is a 30%+ regression in tab-switch latency. If you need a new step, fold it into Frame 1 (destabilizing) or Frame 2 (single authoritative restore).</li><li><strong><code>Pane.lockScroll()</code> locks distance-from-bottom, not viewportY.</strong> Saving an absolute index is broken because the buffer length can change while the tab is hidden (#305). See <code>pane.ts:1071</code>.</li><li><strong>Hidden tabs queue PTY writes — they don&#39;t drop them.</strong> The cap is 128 KB; over the cap, oldest data is discarded. Tabs that print megabytes per second while hidden will lose history, by design.</li><li><strong>Polling is centralized.</strong> Don&#39;t add a per-tab <code>setInterval</code>. Use <code>startCentralPoll()</code> and add your work to <code>Tab.pollProcessInfo()</code>.</li><li><strong>Defaults live in <code>config.ts</code>, schemas in <code>config-types.ts</code>.</strong> Don&#39;t hardcode defaults elsewhere. <code>validateConfig()</code> falls back per-field, never refuses to start.</li><li><strong>The session format is versioned.</strong> Change <code>V2</code> → <code>V3</code> if you change the schema, and add a normalizer in <code>loadSession()</code> so old session files keep loading.</li></ul>`,63)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
